--- a/counter.v
+++ b/counter.v
@@ -1,15 +1,15 @@
 module counter_8bit(
   input clk,
   input rst,
   input [7:0] load_val,
   input load_en,
   output [7:0] count
 );
   reg [7:0] counter;
   always @(posedge clk) begin
     if (rst) counter <= 8'b0;
     else if (load_en) counter <= load_val;
     else counter <= counter + 1;
   end
   assign count = counter;
 endmodule

 module system(
   input clock, reset,
-  input [7:0] initial_value
+  input [7:0] initial_value,
+  input enable
 );
-  counter_8bit cnt(.clk(clock), .rst(reset), .load_val(initial_value), .load_en(enable), .count());
+  counter_8bit cnt(.clk(clock), .rst(reset), .load_val(initial_value), .load_en(enable));
 endmodule

